INSERT INTO "pages" ("id", "title", "slug", "content", "excerpt", "cover_image", "template", "status", "show_in_menu", "menu_title", "sort_order", "meta_title", "meta_description", "published_at", "created_at", "updated_at") VALUES (1, 'О компании', 'about', '<h2>Про наш магазин</h2><p>Ми продаємо якісну електроніку з 2015 року.</p>', 'Історія та цінності нашого магазину', NULL, 'default', 'published', true, 'Про нас', 1, 'О компании — Магазин', NULL, '2026-06-09T19:36:30.511Z', '2026-07-09T19:36:30.511Z', '2026-07-09T19:36:30.511Z') ON CONFLICT DO NOTHING;
INSERT INTO "pages" ("id", "title", "slug", "content", "excerpt", "cover_image", "template", "status", "show_in_menu", "menu_title", "sort_order", "meta_title", "meta_description", "published_at", "created_at", "updated_at") VALUES (2, 'Доставка и оплата', 'delivery-payment', '<h2>Умови доставки</h2><p>Доставляємо Новою Поштою та Укрпоштою по всій Україні.</p>', 'Все способы доставки и оплаты', NULL, 'default', 'published', true, 'Доставка', 2, 'Доставка и оплата', NULL, '2026-06-19T19:36:30.511Z', '2026-07-09T19:36:30.511Z', '2026-07-09T19:36:30.511Z') ON CONFLICT DO NOTHING;
INSERT INTO "pages" ("id", "title", "slug", "content", "excerpt", "cover_image", "template", "status", "show_in_menu", "menu_title", "sort_order", "meta_title", "meta_description", "published_at", "created_at", "updated_at") VALUES (3, 'Контакты', 'contacts', '<h2>Наші контакти</h2><p>Телефон: +380 44 123 45 67</p>', 'Свяжитесь с нами', NULL, 'contacts', 'published', true, 'Контакты', 3, 'Контакты', NULL, '2026-06-24T19:36:30.511Z', '2026-07-09T19:36:30.511Z', '2026-07-09T19:36:30.511Z') ON CONFLICT DO NOTHING;
INSERT INTO "pages" ("id", "title", "title_ru", "slug", "content", "content_ru", "excerpt", "cover_image", "template", "status", "show_in_menu", "menu_title", "sort_order", "meta_title", "meta_description", "published_at", "created_at", "updated_at") VALUES (4, 'Політика конфіденційності', 'Политика конфиденциальности', 'privacy', '<p>Ми поважаємо вашу приватність та захищаємо персональні дані відповідно до законодавства України.</p><h2>1. Збір даних</h2><p>Ми збираємо лише ті дані, які необхідні для оформлення та доставки замовлення.</p><h2>2. Використання даних</h2><p>Персональні дані використовуються виключно для обробки замовлень та зв''язку з вами.</p><h2>3. Захист даних</h2><p>Ми вживаємо всіх необхідних заходів для захисту ваших персональних даних.</p>', '<p>Мы уважаем вашу конфиденциальность и защищаем персональные данные в соответствии с законодательством Украины.</p><h2>1. Сбор данных</h2><p>Мы собираем только те данные, которые необходимы для оформления и доставки заказа.</p><h2>2. Использование данных</h2><p>Персональные данные используются исключительно для обработки заказов и связи с вами.</p><h2>3. Защита данных</h2><p>Мы принимаем все необходимые меры для защиты ваших персональных данных.</p>', '', NULL, 'default', 'published', false, NULL, 4, NULL, NULL, '2026-07-09T19:36:30.511Z', '2026-07-09T19:36:30.511Z', '2026-07-09T19:36:30.511Z') ON CONFLICT DO NOTHING;
INSERT INTO "pages" ("id", "title", "title_ru", "slug", "content", "content_ru", "excerpt", "cover_image", "template", "status", "show_in_menu", "menu_title", "sort_order", "meta_title", "meta_description", "published_at", "created_at", "updated_at") VALUES (5, 'Угода користувача', 'Пользовательское соглашение', 'terms', '<p>Ця Угода користувача регулює використання інтернет-магазину. Користуючись сайтом, ви погоджуєтесь з умовами цієї Угоди.</p><h2>1. Загальні положення</h2><p>Адміністрація сайту надає користувачу доступ до перегляду та замовлення товарів.</p><h2>2. Замовлення</h2><p>Оформлюючи замовлення, користувач підтверджує достовірність наданих даних.</p><h2>3. Відповідальність</h2><p>Сторони несуть відповідальність згідно з чинним законодавством України.</p>', '<p>Настоящее Пользовательское соглашение регулирует использование интернет-магазина. Используя сайт, вы соглашаетесь с условиями данного Соглашения.</p><h2>1. Общие положения</h2><p>Администрация сайта предоставляет пользователю доступ к просмотру и заказу товаров.</p><h2>2. Заказы</h2><p>Оформляя заказ, пользователь подтверждает достоверность предоставленных данных.</p><h2>3. Ответственность</h2><p>Стороны несут ответственность в соответствии с действующим законодательством Украины.</p>', '', NULL, 'default', 'published', false, NULL, 5, NULL, NULL, '2026-07-09T19:36:30.511Z', '2026-07-09T19:36:30.511Z', '2026-07-09T19:36:30.511Z') ON CONFLICT DO NOTHING;
INSERT INTO "pages" ("id", "title", "title_ru", "slug", "content", "content_ru", "excerpt", "cover_image", "template", "status", "show_in_menu", "menu_title", "sort_order", "meta_title", "meta_description", "published_at", "created_at", "updated_at") VALUES (6, 'Політика повернення', 'Политика возвратов', 'returns', '<p>Ви можете повернути товар протягом 14 днів з моменту отримання згідно із Законом України «Про захист прав споживачів».</p><h2>1. Умови повернення</h2><p>Товар має бути у непошкодженому вигляді, зі збереженням товарного вигляду та упаковки.</p><h2>2. Як оформити повернення</h2><p>Зв''яжіться з нашою службою підтримки для оформлення заявки на повернення.</p><h2>3. Повернення коштів</h2><p>Кошти повертаються протягом 7 робочих днів після отримання товару.</p>', '<p>Вы можете вернуть товар в течение 14 дней с момента получения согласно Закону Украины «О защите прав потребителей».</p><h2>1. Условия возврата</h2><p>Товар должен быть в неповреждённом виде, с сохранением товарного вида и упаковки.</p><h2>2. Как оформить возврат</h2><p>Свяжитесь с нашей службой поддержки для оформления заявки на возврат.</p><h2>3. Возврат средств</h2><p>Средства возвращаются в течение 7 рабочих дней после получения товара.</p>', '', NULL, 'default', 'published', false, NULL, 6, NULL, NULL, '2026-07-09T19:36:30.511Z', '2026-07-09T19:36:30.511Z', '2026-07-09T19:36:30.511Z') ON CONFLICT DO NOTHING;
INSERT INTO "pages" ("id", "title", "title_ru", "slug", "content", "content_ru", "excerpt", "cover_image", "template", "status", "show_in_menu", "menu_title", "sort_order", "meta_title", "meta_description", "published_at", "created_at", "updated_at") VALUES (7, 'Доставка та оплата', 'Доставка и оплата', 'delivery', '<p>Ми доставляємо замовлення по всій Україні зручними для вас способами.</p><h2>1. Способи доставки</h2><ul><li>Нова Пошта — 1-3 робочі дні</li><li>Укрпошта — 3-7 робочих днів</li><li>Кур''єрська доставка по місту</li></ul><h2>2. Способи оплати</h2><ul><li>Накладений платіж при отриманні</li><li>Оплата картою онлайн</li><li>Безготівковий розрахунок</li></ul><h2>3. Вартість доставки</h2><p>Вартість доставки розраховується за тарифами перевізника.</p>', '<p>Мы доставляем заказы по всей Украине удобными для вас способами.</p><h2>1. Способы доставки</h2><ul><li>Нова Пошта — 1-3 рабочих дня</li><li>Укрпошта — 3-7 рабочих дней</li><li>Курьерская доставка по городу</li></ul><h2>2. Способы оплаты</h2><ul><li>Наложенный платёж при получении</li><li>Оплата картой онлайн</li><li>Безналичный расчёт</li></ul><h2>3. Стоимость доставки</h2><p>Стоимость доставки рассчитывается по тарифам перевозчика.</p>', '', NULL, 'default', 'published', false, NULL, 7, NULL, NULL, '2026-07-09T19:36:30.511Z', '2026-07-09T19:36:30.511Z', '2026-07-09T19:36:30.511Z') ON CONFLICT DO NOTHING;
